/**
 * Hook Trigger: after_user_create
 * Description: Fetches full user details (including metadata) and seeds the profile collection.
 */
export default async function(req) {
  const eventData = req.data; // { id: number, email: string, role: string }

  // 1. Fetch full user object to obtain the registration metadata
  const user = await $db.users.get(eventData.email);
  if (!user) {
    console.error(`[after_user_create] Unable to resolve user details for email: ${eventData.email}`);
    return;
  }

  const meta = user.metadata || {};

  // 2. Prepare the users_profiles record payload
  const profilePayload = {
    user_id: user.id, // Relational owner field linking to the core user
    email: user.email,
    name: meta.name || user.email.split('@')[0],
    role: user.role,
    avatar: meta.avatar || `https://api.dicebear.com/7.x/pixel-art/svg?seed=${user.id}`,
    bio: meta.bio || '',
    expertise: meta.expertise || [],
    hourlyRate: Number(meta.hourlyRate) || 35,
    completedTasks: 0,
    balance: user.role === 'student' ? 300 : 0, // Balance initialization
    reviewsCount: 0,
    enrolledCourseIds: []
  };

  // 3. Create the record in the users_profiles collection
  try {
    const newProfile = await $db.records.create('users_profiles', profilePayload);
    console.log(`[after_user_create] Successfully seeded users_profiles record (ID: ${newProfile.id}) for user_id: ${user.id}`);
  } catch (err) {
    console.error(`[after_user_create] Failed to seed users_profiles collection: ${err}`);
  }
}
